import './index.css';

import {
  useState
} from 'react';

import {
  createStudent
} from '../../services/studentService';

function AddStudentPage() {

  const [formData, setFormData] =
    useState({

      name: '',
      email: '',
      password: '',
      role: 'student'

    });

  const handleChange =
    (e) => {

    setFormData({

      ...formData,

      [e.target.name]:
      e.target.value

    });

  };

  const handleSubmit =
    async (e) => {

    e.preventDefault();

    try {

      await createStudent(formData);

      alert(
        'Student Added Successfully'
      );

      setFormData({

        name: '',
        email: '',
        password: '',
        role: 'student'

      });

    } catch (error) {

      console.log(error);

      alert(
        error.response?.data?.message
      );

    }

  };

  return (

    <div className="page">

      <h1>
        Add Student
      </h1>

      <form
        className="form"
        onSubmit={handleSubmit}
      >

        <input
          type="text"
          name="name"
          placeholder="Student Name"
          value={formData.name}
          onChange={handleChange}
        />

        <input
          type="email"
          name="email"
          placeholder="Student Email"
          value={formData.email}
          onChange={handleChange}
        />

        <input
          type="password"
          name="password"
          placeholder="Password"
          value={formData.password}
          onChange={handleChange}
        />

        <button type="submit">

          Add Student

        </button>

      </form>

    </div>

  );

}

export default AddStudentPage;
